import React, { FC, useCallback, useRef, useMemo } from 'react';
import { useFocusEffect, useNavigation } from '@react-navigation/native';
import { Dimensions } from 'react-native';
import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
import { ScreenProps } from '../../routes/Models';
import { eventScreenViewV3, eventModalView, eventSelectContent } from '~/constants/functions';
import MyOrdersDetailView from './view';
import { useShallow } from "zustand/react/shallow";
import { useRootStore } from '../../store';
import { OrderDetailStatus, TransactionType } from '../../store/rewardProgram/models';
import { getOrderDetail } from '../../store/rewardProgram/services';
import { formatToCurrency } from '../../utils/functions';
import { moment } from '../../services/moment';
import {
  getTransactionGainType,
  getFormattedPointsValue,
  getFormattedHighlightText,
  getFormattedPointsValueForMarketplace,
  getPaymentTypeLabel,
  getMarketplaceTitle,
  getCleanedImageUrl,
} from './utils';
import { MarketplaceContentData, MarketplaceItemData, STATUS_COLORS } from './Models';

const MyOrdersDetails: FC<ScreenProps<'MyOrdersDetails'>> = ({
  navigation,
  route,
}) => {
  const hasFocused = useRef(false);
  const modalizeRef = useRef<PropsModalizeRef>(null);
  const modalizeRefInfo = useRef<PropsModalizeRef>(null);

  const { orderDetail, orderDetailActions } =
    useRootStore(
      useShallow((state) => ({
        orderDetail: state.orderDetail,
        orderDetailActions: state.orderDetailActions,
      })),
    );

  const transactionId = route.params?.transactionId;
  const passedType = route.params?.type;
  const passedIcon = route.params?.icon;
  const passedStatus = route.params?.status;
  const passedOrigination = route.params?.origination;

  useFocusEffect(
    useCallback(() => {
      if (!hasFocused.current) {
        eventScreenViewV3(  
          'detalhe_pedido',
          'hub_recompensas_spmais',
          'monetizacao',
          {
            location_1: 'monetizacao',
            location_2: 'hub_recompensas_spmais',
            location_3: 'detalhe_pedido',
          });
        hasFocused.current = true;
      }

      if (transactionId) {
        orderDetailActions.reset();
        getOrderDetail({ transactionId });
      }

      return () => {
        hasFocused.current = false;
        orderDetailActions.reset();
      };
    }, [transactionId, orderDetailActions])
  );

  const handleGoBack = () => {
    navigation.goBack();
  };

  const handleOpenReportProblem = () => {
    eventSelectContent({
      content_type: 'cta',
      content_id: 'relatar_problema',
      location_1: 'monetizacao',
      location_2: 'hub_recompensas_spmais',
      location_3: 'detalhe_pedido',
    });

    eventModalView({
      content_id: 'contato_telefones',
      location_1: 'monetizacao',
      location_2: 'hub_recompensas_spmais',
      location_3: 'detalhe_pedido',
    });

    modalizeRef.current?.open?.();
  };

  const handleCloseReportProblem = () => {
    modalizeRef.current?.close?.();
  };

  const handleOpenInfo = () => {
    modalizeRefInfo.current?.open?.();
  };

  const handleCloseInfo = () => {
    modalizeRefInfo.current?.close?.();
  };

  const isLoading = orderDetail.status === OrderDetailStatus.LOADING;
  const hasError = orderDetail.status === OrderDetailStatus.ERROR;
  const { height } = Dimensions.get('window');

  const handleRetry = () => {
    if (transactionId) {
      getOrderDetail({ transactionId });
    }
  };

  const transaction = orderDetail.orderDetail;

  const isValidTransactionType = (type: string | undefined): type is TransactionType => {
    return type === 'CREDIT' || type === 'RESCUE' || type === 'EXPIRED' || type === 'REFUNDED';
  };

  const enrichedTransaction = transaction ? {
    ...transaction,
    type: isValidTransactionType(passedType) ? passedType : transaction.type,
    icon: passedIcon || transaction.icon,
    status: passedStatus || transaction.status,
    details: {
      ...transaction.details,
      provider: passedOrigination || transaction.details?.provider || '',
    },
  } : undefined;

  const isCashback = passedType === 'RESCUE';

  const processedData = useMemo(() => {
    if (!enrichedTransaction) {
      return {
        cardTitle: '',
        formattedPointsValue: '',
        highlightText: '',
        formattedCurrencyValue: '',
        marketplaceContent: undefined,
        showOrderNumber: false,
        showStatus: false,
        showValue: false,
      };
    }

    const gainType = getTransactionGainType(enrichedTransaction);
    const formattedCurrencyValue = formatToCurrency(enrichedTransaction.currencyValue);
    const marketplaceValuePoints = enrichedTransaction?.marketplace?.valuePoints;
    const formattedPointsValue = marketplaceValuePoints !== undefined && marketplaceValuePoints !== null
      ? `- ${getFormattedPointsValueForMarketplace(marketplaceValuePoints)}`
      : getFormattedPointsValue(enrichedTransaction.amount, enrichedTransaction.type);
    const marketplaceTitle = getMarketplaceTitle(enrichedTransaction);
    const cardTitle = marketplaceTitle || enrichedTransaction.description || '';
    const highlightText = getFormattedHighlightText(enrichedTransaction.date, gainType, moment);

    const isMarketplace = !!enrichedTransaction?.marketplace;
    const marketplace = enrichedTransaction?.marketplace;

    let marketplaceContent: MarketplaceContentData | undefined;
    if (isMarketplace && marketplace) {
      const firstOrder = marketplace.orders?.[0];
      const firstPayment = marketplace.payments?.[0];
      const vendorName = firstOrder?.vendor || '';

      const items: MarketplaceItemData[] = [];
      marketplace.orders?.forEach(order => {
        order.items?.forEach(item => {
          items.push({
            name: item.name,
            quantity: item.quantity,
            valuePoints: getFormattedPointsValueForMarketplace(item.valuePoints),
            imageUrl: item.imageUrl,
            cleanedImageUrl: getCleanedImageUrl(item.imageUrl),
          });
        });
      });

      marketplaceContent = {
        orderNumber: enrichedTransaction.id,
        status: enrichedTransaction.status,
        statusColor: enrichedTransaction.status ? (STATUS_COLORS[enrichedTransaction.status] || 'neutral') : undefined,
        paymentType: firstPayment ? getPaymentTypeLabel(firstPayment.paymentType) : undefined,
        shippingValuePoints: marketplace.shippingValuePoints !== undefined && marketplace.shippingValuePoints !== null
          ? getFormattedPointsValueForMarketplace(marketplace.shippingValuePoints)
          : undefined,
        valuePoints: marketplace.valuePoints !== undefined && marketplace.valuePoints !== null
          ? getFormattedPointsValueForMarketplace(marketplace.valuePoints)
          : undefined,
        vendorName: vendorName || undefined,
        items,
      };
    }

    return {
      cardTitle,
      formattedPointsValue,
      highlightText,
      formattedCurrencyValue,
      marketplaceContent,
      showOrderNumber: !isMarketplace,
      showStatus: !isMarketplace,
      showValue: !isMarketplace,
    };
  }, [enrichedTransaction]);

  return (
    <MyOrdersDetailView
      handleGoBack={handleGoBack}
      transaction={enrichedTransaction}
      modalizeRef={modalizeRef}
      modalizeRefInfo={modalizeRefInfo}
      handleOpenReportProblem={handleOpenReportProblem}
      handleCloseReportProblem={handleCloseReportProblem}
      handleOpenInfo={handleOpenInfo}
      handleCloseInfo={handleCloseInfo}
      isLoading={isLoading}
      hasError={hasError}
      handleRetry={handleRetry}
      isCashback={isCashback}
      cardTitle={processedData.cardTitle}
      formattedPointsValue={processedData.formattedPointsValue}
      highlightText={processedData.highlightText}
      formattedCurrencyValue={processedData.formattedCurrencyValue}
      marketplaceContent={processedData.marketplaceContent}
      showOrderNumber={processedData.showOrderNumber}
      showStatus={processedData.showStatus}
      showValue={processedData.showValue}
      height={height}
    />
  );
};

export default MyOrdersDetails;

import { Box, Text, TagLabel, Button, BackDropBottom, SeparatorHorizontal, CardActivity, DetailTransactionValue, Alert } from '@semparar/design-system-app';
import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
import React, { FC } from 'react';
import { Linking, ActivityIndicator } from 'react-native';
import theme from '../../styles/theme';
import BasicScreen from '../../atomic/templates/BasicScreen';
import ApiError from '../../atomic/organisms/ApiError';
import { eventSelectContent } from '~/constants/functions';
import { MyOrdersDetailProps, STATUS_COLORS } from './Models';

const MyOrdersDetailView: FC<MyOrdersDetailProps> = ({
  handleGoBack,
  transaction,
  modalizeRef,
  modalizeRefInfo,
  handleOpenReportProblem,
  handleCloseReportProblem,
  handleOpenInfo,
  handleCloseInfo,
  isLoading,
  hasError,
  handleRetry,
  isCashback,
  cardTitle,
  formattedPointsValue,
  highlightText,
  formattedCurrencyValue,
  marketplaceContent,
  showOrderNumber,
  showStatus,
  showValue,
  height,
}) => {

  if (hasError) {
    return (
      <BasicScreen
        title="Detalhes do pedido"
        leftIconOnPress={handleGoBack}
        errorButtonOnPress={handleRetry || (() => {})}
      >
        <ApiError
          title="Algo deu errado!"
          subTitle="Por favor, tente de novo."
          isLoading={isLoading}
          onPress={handleRetry || (() => {})}
        />
      </BasicScreen>
    );
  }

  if (isLoading && !transaction) {
    return (
      <BasicScreen
        title="Detalhes do pedido"
        leftIconOnPress={handleGoBack}
        hasScroll
        errorButtonOnPress={() => {}}
      >
        <Box flex={1} justify="center" align="center" minHeight={400}>
          <ActivityIndicator size="large" color={theme.colors.BRAND_BASE_01} />
        </Box>
      </BasicScreen>
    );
  }

  if (!transaction) {
    return null;
  }

  const renderDivider = () => {
    return (
      <SeparatorHorizontal
        borderWidth="smaller"
        borderColor="BRAND_COMPLEMENT_02"
        height={1}
        width="100%"
        mt="xxxxs"
      />
    );
  };

  const renderMarketplaceContent = () => {
    if (!marketplaceContent) return null;

    return (
      <>
        <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs" mt="xxxxs">
          Número do pedido
        </Text>
        <Text type="paragraphMD" color="INTENSE_COLOR_03">
          #{marketplaceContent.orderNumber}
        </Text>
        {marketplaceContent.status && (
          <>
            {renderDivider()}
            <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs" mt="xxxxs">
              Status do pedido
            </Text>
            <TagLabel
              type={(marketplaceContent.statusColor as any) || 'neutral'}
              text={marketplaceContent.status}
              showSpacing
            />
          </>
        )}
        {marketplaceContent.paymentType && (
          <>
            {renderDivider()}
            <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs" mt="xxxxs">
              Forma de pagamento
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {marketplaceContent.paymentType}
            </Text>
          </>
        )}
        {marketplaceContent.shippingValuePoints !== undefined && marketplaceContent.shippingValuePoints !== null && (
          <>
            {renderDivider()}
            <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs" mt="xxxxs">
              Frete
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {marketplaceContent.shippingValuePoints}
            </Text>
          </>
        )}
        {marketplaceContent.valuePoints !== undefined && marketplaceContent.valuePoints !== null && (
          <>
            {renderDivider()}
            <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs" mt="xxxxs">
              Valor total
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {marketplaceContent.valuePoints}
            </Text>
          </>
        )}
        {marketplaceContent.vendorName && (
          <>
            {renderDivider()}
            <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs" mt="xxxxs">
              Parceiro: {marketplaceContent.vendorName}
            </Text>
          </>
        )}
        {marketplaceContent.items.map((item, itemIndex: number) => (
          <CardActivity
            key={itemIndex}
            mt={"nano"}
            title={item.name}
            titleTextType="paragraphMD"
            description={`Quantidade: ${item.quantity}\nValor: ${item.valuePoints}`}
            descriptionTextType="paragraphSM"
            showImage={!!item.cleanedImageUrl}
            image={item.cleanedImageUrl ? { uri: item.cleanedImageUrl } : undefined}
            showIcon={false}
            iconRight={null as any}
            hideBorder={false}
          />
        ))}

        <Alert
          title='Detalhes da entrega'
          mt="meddium"
          label="Você pode acompanhar a entrega do seu pedido pelo site do parceiro."
          numberOfLines={2}
          type="highlight"
          icon="icon-truck"
          hasIconBackground
          bgIconColor="BRAND_COMPLEMENT_03"
        />
      </>
    );
  };

  return (
    <>
      <BasicScreen
        title={'Detalhes do pedido'}
        isLoading={isLoading}
        leftIconOnPress={handleGoBack}
        rightIcon={isCashback && !transaction?.marketplace ? "icon-help" : undefined}
        rightIconOnPress={undefined}
        hasRightIcon={isCashback && !transaction?.marketplace}
        hasScroll
        errorButtonOnPress={() => { }}
      >
      <DetailTransactionValue
          icon={transaction.icon as any}
          title={cardTitle}
          titleColor="BRAND_COMPLEMENT_01"
          iconBgColor="BRAND_COMPLEMENT_03"
          points={formattedPointsValue}
          bgColor="BRAND_COMPLEMENT_02"
          pointsColor={(transaction.type === 'CREDIT' || transaction.type === 'REFUNDED') ? 'PLUS_COLOR_02' : 'INTENSE_COLOR_05' as const}
        />

        <Box ml='smaller' mr='smaller' mt='xs' flex={1}>

          <TagLabel
            icon={undefined}
            type="neutral"
            text={highlightText}
            showSpacing
            mb='xs'
          />

          <Box flex={1} width="100%">
            {showOrderNumber && (
              <>
                <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs">
                  Número do pedido
                </Text>
                <Text type="paragraphMD" color="INTENSE_COLOR_03">
                  #{transaction.id}
                </Text>
              </>
            )}

            {showStatus && transaction.status && (
              <>
                {renderDivider()}
                <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs" mt="xxxxs">
                  Status do pedido
                </Text>
                <TagLabel
                  type={STATUS_COLORS[transaction.status] || 'neutral'}
                  text={transaction.status}
                  showSpacing
                />
              </>
            )}

            {showValue && (
              <>
                {renderDivider()}
                <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs" mt="xxxxs">
                  Valor
                </Text>
                <Text type="paragraphMD" color="INTENSE_COLOR_03">
                  {formattedCurrencyValue}
                </Text>
              </>
            )}

            {marketplaceContent && renderMarketplaceContent()}
          </Box>


          <Box width="100%" align="flex-end" mb="small">
            <Button
              type="ghostLarge"
              text="Relatar Problema"
              onPress={handleOpenReportProblem}
            />
          </Box>
        </Box>

      </BasicScreen>

      <BackDropBottom
        modalizeRef={modalizeRef as PropsModalizeRef}
      >
        <Box align="center" width="100%" mt="xxs">
          <Box align="center" width="100%">
            <Text type="paragraphXXXL" color="BRAND_COMPLEMENT_01" mb="xs" align="center">
              Central de Atendimento
            </Text>
          </Box>
        </Box>

        <Box pd="innerSmall">
          <CardActivity
            mt="nano"
            icon="icon-contact"
            title="Capitais"
            description="4002 1552"
            iconRight="icon-next"
            showIcon
            showTagLabel={false}
            onPress={() => {
              eventSelectContent({
                content_type: 'cta',
                content_id: 'telefones_capitais',
                location_1: 'monetizacao',
                location_2: 'hub_recompensas_spmais',
                location_3: 'contato_telefones',
              });
              Linking.openURL('tel:40021552');
            }}
          />

          <CardActivity
            mt="nano"
            icon="icon-contact"
            title="Demais localidades"
            description="0800 015 0252"
            iconRight="icon-next"
            showIcon
            showTagLabel={false}
            onPress={() => {
              eventSelectContent({
                content_type: 'cta',
                content_id: 'telefones_demais_localidades',
                location_1: 'monetizacao',
                location_2: 'hub_recompensas_spmais',
                location_3: 'contato_telefones',
              });

              Linking.openURL('tel:08000150252');
            }}
          />
          <Text type="paragraphXS" color="INTENSE_COLOR_04" mt='xxxxs'>
            *Atendimento de segunda à sexta das 9h às 21h. Sábado e domingo das 9h às 17h.
          </Text>


        </Box>

        <Box align="center" width="100%" mt='xxxxs'>
          <Text type="linkMD" color="INTENSE_COLOR_05" onPress={handleCloseReportProblem} align="center">
            Fechar
          </Text>
        </Box>
      </BackDropBottom>

      {isCashback && (
        <BackDropBottom modalHeight={height * 0.30} modalizeRef={modalizeRefInfo as PropsModalizeRef}>
          <Text
            type="paragraphMD"
            align="center"
            color="INTENSE_COLOR_05"
            mt="small"
            mb="smaller"
          >
            Você também pode conferir o valor do desconto nos lançamentos da sua fatura.
          </Text>

          <Button text="Entendi" onPress={handleCloseInfo} />
        </BackDropBottom>
      )}
    </>
  );
};

export default MyOrdersDetailView;

